mapper.select:
SELECT
CASE WHEN ri.type = 'buy' THEN '采购单' WHEN ri.type = 'sell' THEN '销售单' WHEN ri.type = 'bre' THEN '采购退货单' WHEN ri.type = 'sre' THEN '销售退货单' WHEN ri.type = 'swapOut' THEN '调拨单-出' WHEN ri.type = 'swapEnter' THEN '调拨单-入' WHEN ri.type = 'entry' THEN '其它入库单' WHEN ri.type = 'extry' THEN '其它出库单' ELSE ri.type END as type,
ri.direction as direction,
ri.nums as nums,
DATE(ri.time) as `time`,
CASE WHEN ri.type = 'buy' THEN b.id WHEN ri.type = 'sell' THEN s.id WHEN ri.type = 'bre' THEN br.id WHEN ri.type = 'sre' THEN sr.id WHEN ri.type = 'swapOut' THEN sw.id WHEN ri.type = 'swapEnter' THEN sw.id WHEN ri.type = 'entry' THEN e.id WHEN ri.type = 'extry' THEN ex.id ELSE NULL END as id,
CASE WHEN ri.type = 'buy' THEN b.number WHEN ri.type = 'sell' THEN s.number WHEN ri.type = 'bre' THEN br.number WHEN ri.type = 'sre' THEN sr.number WHEN ri.type = 'swapOut' THEN sw.number WHEN ri.type = 'swapEnter' THEN sw.number WHEN ri.type = 'entry' THEN e.number WHEN ri.type = 'extry' THEN ex.number ELSE '' END as number,
CASE WHEN ri.type = 'buy' THEN f_b.id WHEN ri.type = 'sell' THEN f_s.id WHEN ri.type = 'bre' THEN f_br.id WHEN ri.type = 'sre' THEN f_sr.id WHEN ri.type = 'swapOut' THEN f_sw.id WHEN ri.type = 'swapEnter' THEN f_sw.id WHEN ri.type = 'entry' THEN f_e.id WHEN ri.type = 'extry' THEN f_ex.id ELSE NULL END as frameId,
CASE WHEN ri.type = 'buy' THEN f_b.name WHEN ri.type = 'sell' THEN f_s.name WHEN ri.type = 'bre' THEN f_br.name WHEN ri.type = 'sre' THEN f_sr.name WHEN ri.type = 'swapOut' THEN f_sw.name WHEN ri.type = 'swapEnter' THEN f_sw.name WHEN ri.type = 'entry' THEN f_e.name WHEN ri.type = 'extry' THEN f_ex.name ELSE '' END as frameName
FROM room_info ri
LEFT JOIN buy_info ri_buy ON ri.type = 'buy' AND ri.info = ri_buy.id LEFT JOIN sell_info ri_sell ON ri.type = 'sell' AND ri.info = ri_sell.id LEFT JOIN bre_info ri_bre ON ri.type = 'bre' AND ri.info = ri_bre.id LEFT JOIN sre_info ri_sre ON ri.type = 'sre' AND ri.info = ri_sre.id LEFT JOIN swap_info ri_swap ON (ri.type = 'swapOut' OR ri.type = 'swapEnter') AND ri.info = ri_swap.id LEFT JOIN entry_info ri_entry ON ri.type = 'entry' AND ri.info = ri_entry.id LEFT JOIN extry_info ri_extry ON ri.type = 'extry' AND ri.info = ri_extry.id
LEFT JOIN buy b ON ri.type = 'buy' AND ri.class = b.id LEFT JOIN frame f_b ON b.frame = f_b.id
LEFT JOIN sell s ON ri.type = 'sell' AND ri.class = s.id LEFT JOIN frame f_s ON s.frame = f_s.id
LEFT JOIN bre br ON ri.type = 'bre' AND ri.class = br.id LEFT JOIN frame f_br ON br.frame = f_br.id
LEFT JOIN sre sr ON ri.type = 'sre' AND ri.class = sr.id LEFT JOIN frame f_sr ON sr.frame = f_sr.id
LEFT JOIN swap sw ON (ri.type = 'swapOut' OR ri.type = 'swapEnter') AND ri.class = sw.id LEFT JOIN frame f_sw ON sw.frame = f_sw.id
LEFT JOIN entry e ON ri.type = 'entry' AND ri.class = e.id LEFT JOIN frame f_e ON e.frame = f_e.id
LEFT JOIN extry ex ON ri.type = 'extry' AND ri.class = ex.id LEFT JOIN frame f_ex ON ex.frame = f_ex.id
AND ( (ri.type = 'buy' AND ri_buy.goods = #{query.goodsId}) OR (ri.type = 'sell' AND ri_sell.goods = #{query.goodsId}) OR (ri.type = 'bre' AND ri_bre.goods = #{query.goodsId}) OR (ri.type = 'sre' AND ri_sre.goods = #{query.goodsId}) OR ((ri.type = 'swapOut' OR ri.type = 'swapEnter') AND ri_swap.goods = #{query.goodsId}) OR (ri.type = 'entry' AND ri_entry.goods = #{query.goodsId}) OR (ri.type = 'extry' AND ri_extry.goods = #{query.goodsId}) )
AND ( (ri.type = 'buy' AND ri_buy.attr = #{query.attrName}) OR (ri.type = 'sell' AND ri_sell.attr = #{query.attrName}) OR (ri.type = 'bre' AND ri_bre.attr = #{query.attrName}) OR (ri.type = 'sre' AND ri_sre.attr = #{query.attrName}) OR ((ri.type = 'swapOut' OR ri.type = 'swapEnter') AND ri_swap.attr = #{query.attrName}) OR (ri.type = 'entry' AND ri_entry.attr = #{query.attrName}) OR (ri.type = 'extry' AND ri_extry.attr = #{query.attrName}) )
AND (
(ri.type = 'buy' AND ri_buy.warehouse IN
#{warehouseId}
) OR (ri.type = 'sell' AND ri_sell.warehouse IN
#{warehouseId}
) OR (ri.type = 'bre' AND ri_bre.warehouse IN
#{warehouseId}
) OR (ri.type = 'sre' AND ri_sre.warehouse IN
#{warehouseId}
) OR
(ri.type = 'swapOut' AND ri_swap.warehouse IN
#{warehouseId}
) OR (ri.type = 'swapEnter' AND ri_swap.storehouse IN
#{warehouseId}
) OR (ri.type = 'entry' AND ri_entry.warehouse IN
#{warehouseId}
) OR (ri.type = 'extry' AND ri_extry.warehouse IN
#{warehouseId}
) )
AND ri.type IN
#{type}
AND ( (ri.type = 'buy' AND b.number LIKE CONCAT('%', #{query.documentNumber}, '%')) OR (ri.type = 'sell' AND s.number LIKE CONCAT('%', #{query.documentNumber}, '%')) OR (ri.type = 'bre' AND br.number LIKE CONCAT('%', #{query.documentNumber}, '%')) OR (ri.type = 'sre' AND sr.number LIKE CONCAT('%', #{query.documentNumber}, '%')) OR ((ri.type = 'swapOut' OR ri.type = 'swapEnter') AND sw.number LIKE CONCAT('%', #{query.documentNumber}, '%')) OR (ri.type = 'entry' AND e.number LIKE CONCAT('%', #{query.documentNumber}, '%')) OR (ri.type = 'extry' AND ex.number LIKE CONCAT('%', #{query.documentNumber}, '%')) )
AND ( (ri.type = 'buy' AND DATE(b.time) >= #{query.startDate}) OR (ri.type = 'sell' AND DATE(s.time) >= #{query.startDate}) OR (ri.type = 'bre' AND DATE(br.time) >= #{query.startDate}) OR (ri.type = 'sre' AND DATE(sr.time) >= #{query.startDate}) OR ((ri.type = 'swapOut' OR ri.type = 'swapEnter') AND DATE(sw.time) >= #{query.startDate}) OR (ri.type = 'entry' AND DATE(e.time) >= #{query.startDate}) OR (ri.type = 'extry' AND DATE(ex.time) >= #{query.startDate}) )
AND ( (ri.type = 'buy' AND DATE(b.time) <= #{query.endDate}) OR (ri.type = 'sell' AND DATE(s.time) <= #{query.endDate}) OR (ri.type = 'bre' AND DATE(br.time) <= #{query.endDate}) OR (ri.type = 'sre' AND DATE(sr.time) <= #{query.endDate}) OR ((ri.type = 'swapOut' OR ri.type = 'swapEnter') AND DATE(sw.time) <= #{query.endDate}) OR (ri.type = 'entry' AND DATE(e.time) <= #{query.endDate}) OR (ri.type = 'extry' AND DATE(ex.time) <= #{query.endDate}) )
ORDER BY ri.time DESC
